14	export class ResultsCache {
15	  private cache = new Map<string, SuiteResultCache>()
16	  private workspacesKeyMap = new Map<string, string[]>()
17	  private cachePath: string | null = null
18	  private version: string
19	  private root = '/'
20	
21	  constructor(private logger: Logger) {
22	    this.version = Vitest.version
23	  }
24	
25	  public getCachePath(): string | null {
26	    return this.cachePath
27	  }
28	
29	  setConfig(root: string, config: ResolvedConfig['cache']): void {
30	    this.root = root
31	    if (config) {
32	      this.cachePath = resolve(config.dir, 'results.json')
33	    }
34	  }
35	
36	  getResults(key: string): SuiteResultCache | undefined {
37	    return this.cache.get(key)
38	  }
