export interface DurationObservation {
  duration: number
  recordedAt: number
}

export function smoothDurations(observations: DurationObservation[], strategy: DurationSmoothing): number {
  if (!observations.length) {
    return 0
  }

  if (strategy === 'latest') {
    return observations.reduce((latest, current) =>
      current.recordedAt >= latest.recordedAt ? current : latest,
    ).duration
  }

  if (strategy === 'average') {
    const sum = observations.reduce((acc, obs) => acc + obs.duration, 0)
    return Math.round(sum / observations.length)
  }

  const sorted = [...observations].sort((a, b) => a.duration - b.duration)

  if (strategy === 'p95') {
    const index = Math.ceil(0.95 * sorted.length) - 1
    return sorted[index].duration
  }

  // median
  const mid = sorted.length / 2
  if (Number.isInteger(mid)) {
    return Math.floor((sorted[mid - 1].duration + sorted[mid].duration) / 2)
  }
  return sorted[Math.floor(mid)].duration
}
