import { existsSync, promises as fs } from 'node:fs'
import { slash } from '@vitest/utils/helpers'
import { dirname, relative, resolve } from 'pathe'

export type { DurationObservation }

interface RawDurationEntry {
  duration?: number
  recordedAt?: number
  observations?: { duration: number, recordedAt: number }[]
}

export function resolveDurationHistoryPath(path: string, root: string): string {
  return resolve(root, path)
}

export function normalizeHistoryKey(filePath: string, root: string): string {
  const fullPath = resolve(slash(root), slash(filePath))
  return slash(relative(root, fullPath))
}

function normalizeEntry(entry: unknown): DurationObservation[] | null {
  if (typeof entry === 'number') {
    return [{ duration: entry, recordedAt: 0 }]
  }
  if (entry && typeof entry === 'object') {
    const raw = entry as RawDurationEntry
    if (Array.isArray(raw.observations)) {
      return raw.observations
        .filter(obs => obs && typeof obs.duration === 'number' && typeof obs.recordedAt === 'number')
        .map(obs => ({ duration: obs.duration, recordedAt: obs.recordedAt }))
    }
    if (typeof raw.duration === 'number') {
      return [{
        duration: raw.duration,
        recordedAt: typeof raw.recordedAt === 'number' ? raw.recordedAt : 0,
      }]
    }
  }
  return null
}

export function parseDurationHistory(content: string): Record<string, DurationObservation[]> | null {
  let json: unknown
  try {
    json = JSON.parse(content)
  }
  catch {
    return null
  }

  if (!json || typeof json !== 'object' || Array.isArray(json)) {
    return null
  }

  const result: Record<string, DurationObservation[]> = {}
  for (const [key, value] of Object.entries(json as Record<string, unknown>)) {
    const observations = normalizeEntry(value)
    if (observations) {
      result[key] = observations
    }
  }
  return result
}

export async function readDurationHistory(filePath: string): Promise<Record<string, DurationObservation[]> | null> {
  if (!existsSync(filePath)) {
    return null
  }
  let content: string
  try {
    content = await fs.readFile(filePath, 'utf8')
  }
  catch {
    return null
  }
  return parseDurationHistory(content)
}

export function filterExpired(observations: DurationObservation[], ttl: number, now: number): DurationObservation[] {
  if (ttl <= 0) {
    return observations
  }
  return observations.filter(obs => obs.recordedAt === 0 || obs.recordedAt >= now - ttl)
}

export async function writeDurationHistory(
  filePath: string,
  updates: Map<string, number>,
  maxRuns: number,
  now: number,
): Promise<void> {
  const existing = (await readDurationHistory(filePath)) ?? {}

  for (const [key, duration] of updates) {
    const observations = existing[key] ?? []
    observations.push({ duration, recordedAt: now })
    observations.sort((a, b) => b.recordedAt - a.recordedAt)
    existing[key] = observations.slice(0, maxRuns)
  }

  const serialized: Record<string, unknown> = {}
  for (const [key, observations] of Object.entries(existing)) {
    serialized[key] = maxRuns === 1
      ? { duration: observations[0].duration, recordedAt: observations[0].recordedAt }
      : { observations }
  }

  const dir = dirname(filePath)
  if (!existsSync(dir)) {
    await fs.mkdir(dir, { recursive: true })
  }

  await fs.writeFile(filePath, JSON.stringify(serialized))
}
