export function checkRebalance(loads: number[], threshold: number): string | null {
  if (threshold <= 0 || loads.length === 0) {
    return null
  }
  const maxLoad = Math.max(...loads)
  if (maxLoad <= 0) {
    return null
  }
  const minLoad = Math.min(...loads)
  const ratio = minLoad / maxLoad
  if (ratio < threshold) {
    return `Shards are unevenly balanced: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`
  }
  return null
}

export function splitSlowFiles<T>(
  files: T[],
  durationOf: (item: T) => number,
  threshold: number,
): { slow: T[], remaining: T[] } {
  const slow: T[] = []
  const remaining: T[] = []
  for (const file of files) {
    if (durationOf(file) > threshold) {
      slow.push(file)
    }
    else {
      remaining.push(file)
    }
  }
  return { slow, remaining }
}
