  test('average rounds the mean', () => {
    const observations = [
      { duration: 100, recordedAt: 1 },
      { duration: 201, recordedAt: 2 },
    ]
    expect(smoothDurations(observations, 'average')).toBe(Math.round((100 + 201) / 2))
  })

  test('p95 picks the ceil(0.95n) - 1 index of the sorted list', () => {
    const observations = Array.from({ length: 20 }, (_, i) => ({ duration: (i + 1) * 10, recordedAt: i }))
    // sorted durations: 10..200, index Math.ceil(0.95*20)-1 = 18 -> duration 190
    expect(smoothDurations(observations, 'p95')).toBe(190)
  })

  test('median with even count averages the two middle values', () => {
    const observations = [
      { duration: 10, recordedAt: 1 },
      { duration: 20, recordedAt: 2 },
      { duration: 30, recordedAt: 3 },
      { duration: 40, recordedAt: 4 },
    ]
    expect(smoothDurations(observations, 'median')).toBe(Math.floor((20 + 30) / 2))
  })

