  normalizeHistoryKey,
  parseDurationHistory,
  readDurationHistory,
  writeDurationHistory,
} from '../../../packages/vitest/src/node/duration-history'

describe('parseDurationHistory', () => {
  test('returns null for corrupt JSON', () => {
    expect(parseDurationHistory('{not json')).toBeNull()
  })

  test('returns null for a non-object top level value', () => {
    expect(parseDurationHistory('[1,2,3]')).toBeNull()
    expect(parseDurationHistory('123')).toBeNull()
  })

  test('migrates legacy plain-number entries', () => {
    const result = parseDurationHistory(JSON.stringify({ 'test/a.ts': 5000 }))
    expect(result).toStrictEqual({
      'test/a.ts': [{ duration: 5000, recordedAt: 0 }],
    })
  })

  test('normalizes single-entry shape', () => {
    const result = parseDurationHistory(JSON.stringify({
      'test/a.ts': { duration: 1234, recordedAt: 1700000000 },
    }))
    expect(result).toStrictEqual({
      'test/a.ts': [{ duration: 1234, recordedAt: 1700000000 }],
    })
  })

  test('normalizes multi-observation shape', () => {
    const result = parseDurationHistory(JSON.stringify({
      'test/a.ts': { observations: [{ duration: 1, recordedAt: 1 }, { duration: 2, recordedAt: 2 }] },
    }))
    expect(result).toStrictEqual({
      'test/a.ts': [{ duration: 1, recordedAt: 1 }, { duration: 2, recordedAt: 2 }],
    })
  })
})

describe('filterExpired', () => {
  test('ttl <= 0 keeps everything', () => {
    const observations = [{ duration: 1, recordedAt: 1 }]
    expect(filterExpired(observations, 0, 1000)).toStrictEqual(observations)
  })

  test('drops observations older than now - ttl', () => {
    const observations = [
      { duration: 1, recordedAt: 100 },
      { duration: 2, recordedAt: 900 },
    ]
    expect(filterExpired(observations, 500, 1000)).toStrictEqual([{ duration: 2, recordedAt: 900 }])
  })

  test('recordedAt === 0 never expires', () => {
    const observations = [{ duration: 1, recordedAt: 0 }]
    expect(filterExpired(observations, 1, 100000)).toStrictEqual(observations)
  })
})

describe('normalizeHistoryKey', () => {
  test('produces a slash-normalized path relative to root', () => {
    expect(normalizeHistoryKey('/root/test/a.test.ts', '/root')).toBe('test/a.test.ts')
  })
})

describe('read/writeDurationHistory', () => {
  let dir: string

  beforeEach(() => {
    dir = mkdtempSync(join(tmpdir(), 'vitest-duration-history-'))
  })

  afterEach(() => {
    rmSync(dir, { recursive: true, force: true })
  })

  test('missing file returns null', async () => {
    const result = await readDurationHistory(join(dir, 'missing.json'))
    expect(result).toBeNull()
  })

  test('writes single-entry shape when maxRuns === 1', async () => {
    const filePath = join(dir, 'duration-history.json')
    await writeDurationHistory(filePath, new Map([['test/a.ts', 123]]), 1, 1000)

    const raw = JSON.parse(readFileSync(filePath, 'utf8'))
    expect(raw['test/a.ts']).toStrictEqual({ duration: 123, recordedAt: 1000 })
  })

  test('writes observations shape when maxRuns > 1, capped to maxRuns most recent', async () => {
    const filePath = join(dir, 'duration-history.json')
    await writeDurationHistory(filePath, new Map([['test/a.ts', 100]]), 2, 1000)
    await writeDurationHistory(filePath, new Map([['test/a.ts', 200]]), 2, 2000)
    await writeDurationHistory(filePath, new Map([['test/a.ts', 300]]), 2, 3000)

